======= Fix for sys/net/bridge.c:
755a756,759
>           M_PREPEND(m, ETHER_HDR_LEN, M_DONTWAIT);
>           if (m == NULL)
>                   return ENOBUFS;
>           bcopy(eh, mtod(m, struct ether_header *), ETHER_HDR_LEN);
